:root {
  --size: 70vmin;
  --color-1: #fe3424;
  --color-2: #fdbf36;
  --color-3: #1e69aa;
  --color-4: #000;
}

body {
  display: grid;
  place-items: center;
  min-height: 100vh;
  margin: 0;
}

div {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
}

span {
  display: grid;
  height: calc(var(--size) / 3);
  aspect-ratio: 1;
}

span:before,
span:after {
  content: "";
  grid-row: 1;
  grid-column: 1;
}

div[data-digit="0"] span:nth-child(1) {
  border-radius: 100% 0 0 0;
  background: currentcolor;
}
div[data-digit="0"] span:nth-child(2) {
